// // This module implements an asynchronous reset D flip-flop where the output is set to 1 when the reset is active.
module dff_ar (
    Q,
    CLK,
    D,
    RST
);

    output Q;
    input CLK, D, RST;

    reg Q;

    always @(posedge CLK or negedge RST) begin
        if (!RST) begin
            Q <= 1'b0;
        end else begin
            Q <= D;
        end
    end

endmodule
